    use crate::constants::DISC_NORMAL;
    use crate::signing::derive_signing_key;
    use num_bigint::BigInt;
    use num_rational::BigRational;
    type Q = BigRational;
    fn qr(n: i64, d: i64) -> Q { Q::new(BigInt::from(n), BigInt::from(d)) }

    fn test_receipt() -> MeshReceipt {
        MeshReceipt::build(
            &[0x42; 32], &qr(3, 7), 1, 99,
            &[0u8; 32], DISC_NORMAL, 12345, 0x01, None,
        )
    }

    #[test]
    fn test_native_frame_size() {
        let sk = derive_signing_key(&[0x42; 32]);
        let receipt = test_receipt();
        let frame = frame_signed_receipt(&receipt, &sk);
        assert_eq!(frame.len(), NATIVE_FRAME_SIZE);
    }

    #[test]
    fn test_native_loopback_roundtrip() {
        let origin_rcf = [0x42; 32];
        let sk = derive_signing_key(&origin_rcf);
        let pk = signing::public_key(&sk);
        let receipt = test_receipt();
        let frame = frame_signed_receipt(&receipt, &sk);

        let listener = TcpListener::bind("127.0.0.1:0").unwrap();
        let addr = listener.local_addr().unwrap();

        let send_handle = thread::spawn(move || {
            let mut stream = TcpStream::connect(addr).unwrap();
            stream.write_all(&frame).unwrap();
            stream.flush().unwrap();
        });

        let (mut stream, _) = listener.accept().unwrap();
        stream.set_read_timeout(Some(Duration::from_secs(5))).unwrap();
        let (decoded, hash) = read_validated_frame(&mut stream, &pk).unwrap();

        send_handle.join().unwrap();

        assert_eq!(decoded.k_index, receipt.k_index);
        assert_eq!(decoded.rcf_identity, receipt.rcf_identity);
        assert_eq!(decoded.receipt_hash, receipt.receipt_hash);
        assert!(hash.iter().any(|&b| b != 0));
    }

